                if (version >= 2) {
                    av_log(avctx, AV_LOG_ERROR, "This build does not support decoding VP4.\n");
                    return AVERROR_DECODER_NOT_FOUND;
                }
#endif
                s->version = version;
                if (avctx->frame_number == 0)
                    av_log(s->avctx, AV_LOG_DEBUG,
                           "VP version: %d\n", s->version);
            }
        }
